DELETE FROM qualitative_questions WHERE risk_model_id = riskModelId;
DELETE FROM likelihood_metrics WHERE risk_model_id = riskModelId;
DELETE FROM risk_model_domains WHERE risk_model_id = riskModelId;
delete from quant_metrics_to_data_type_classifications where quant_metric_id in (select qm.id from quant_metrics qm where qm.risk_model_id = riskModelId);
DELETE FROM metric_formula_items WHERE quant_metric_id in (select qm.id from quant_metrics qm where qm.risk_model_id = riskModelId);
DELETE FROM quant_metrics WHERE risk_model_id = riskModelId;
DELETE FROM qual_metrics WHERE risk_model_id = riskModelId;
DELETE FROM metric_formula_items WHERE risk_model_constant_ref_id in (select id FROM risk_model_constants WHERE risk_model_id = riskModelId);
DELETE FROM risk_model_constants WHERE risk_model_id = riskModelId;
DELETE FROM risk_metrics WHERE risk_model_id = riskModelId;
-- DELETE FROM quants WHERE risk_model_id = riskModelId;

DELETE FROM risk_models WHERE id = riskModelId;

RETURN riskModelId;
END;
$$;


ALTER FUNCTION public.delete_risk_model(riskmodelid bigint) OWNER TO pgadmin;

--
-- TOC entry 604 (class 1255 OID 142083)
-- Name: delete_technology_category(integer); Type: FUNCTION; Schema: public; Owner: pgadmin
--

CREATE FUNCTION public.delete_technology_category(source_id integer) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
BEGIN
	DELETE FROM assessment_to_technology_category WHERE technology_category_id = source_id;
	DELETE FROM findings WHERE technology_category_id = source_id;
	DELETE FROM quant_metrics_to_technology_categories WHERE technology_category_id = source_id;
	DELETE FROM technologies WHERE technology_category_id = source_id;
	DELETE FROM vulnerability_to_technology_category WHERE technology_category_id = source_id;
	DELETE FROM technology_categories WHERE id = source_id;

	SELECT 'OK';
END;
$$;


ALTER FUNCTION public.delete_technology_category(source_id integer) OWNER TO pgadmin;

--
-- TOC entry 605 (class 1255 OID 142084)
-- Name: f_user_update_firt_last_name(); Type: FUNCTION; Schema: public; Owner: pgadmin
--

CREATE FUNCTION public.f_user_update_firt_last_name() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
	DECLARE user_id int;
BEGIN
	NEW.full_name = TRIM(CONCAT(NEW.first_name, ' ', NEW.last_name));

	RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_user_update_firt_last_name() OWNER TO pgadmin;

--
-- TOC entry 606 (class 1255 OID 142085)
-- Name: reassign_technology_category(integer, integer); Type: FUNCTION; Schema: public; Owner: pgadmin
--

CREATE FUNCTION public.reassign_technology_category(source_id integer, target_id integer) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
BEGIN
	UPDATE assessment_to_technology_category SET technology_category_id = target_id WHERE technology_category_id = source_id;
	UPDATE findings SET technology_category_id = target_id WHERE technology_category_id = source_id;
	UPDATE quant_metrics_to_technology_categories SET technology_category_id = target_id WHERE technology_category_id = source_id;
	UPDATE technologies SET technology_category_id = target_id WHERE technology_category_id = source_id;
	UPDATE vulnerability_to_technology_category SET technology_category_id = target_id WHERE technology_category_id = source_id;

	SELECT 'OK';
END;
$$;


ALTER FUNCTION public.reassign_technology_category(source_id integer, target_id integer) OWNER TO pgadmin;

--
-- TOC entry 619 (class 1255 OID 142086)
-- Name: search_columns(text, name[], name[]); Type: FUNCTION; Schema: public; Owner: pgadmin
--

CREATE FUNCTION public.search_columns(needle text, haystack_tables name[] DEFAULT '{}'::name[], haystack_schema name[] DEFAULT '{}'::name[]) RETURNS TABLE(schemaname text, tablename text, columnname text, rowctid text)
    LANGUAGE plpgsql
    AS $$
begin
  FOR schemaname,tablename,columnname IN
      SELECT c.table_schema,c.table_name,c.column_name
      FROM information_schema.columns c
        JOIN information_schema.tables t ON
          (t.table_name=c.table_name AND t.table_schema=c.table_schema)
        JOIN information_schema.table_privileges p ON
          (t.table_name=p.table_name AND t.table_schema=p.table_schema
              AND p.privilege_type='SELECT')
        JOIN information_schema.schemata s ON
          (s.schema_name=t.table_schema)
      WHERE (c.table_name=ANY(haystack_tables) OR haystack_tables='{}')
        AND (c.table_schema=ANY(haystack_schema) OR haystack_schema='{}')
        AND t.table_type='BASE TABLE'
  LOOP
    FOR rowctid IN
      EXECUTE format('SELECT ctid FROM %I.%I WHERE cast(%I as text)=%L',
       schemaname,
       tablename,
       columnname,
       needle
      )
    LOOP
      -- uncomment next line to get some progress report
      -- RAISE NOTICE 'hit in %.%', schemaname, tablename;
      RETURN NEXT;
    END LOOP;
 END LOOP;
END;
$$;


ALTER FUNCTION public.search_columns(needle text, haystack_tables name[], haystack_schema name[]) OWNER TO pgadmin;

SET default_tablespace = '';

SET default_table_access_method = heap;

