INSERT INTO public.cyber_roles VALUES (1, NULL, 'Board Member', 'Mandated to establish policies for corporate management and make decisions on major company issues. Fiduciary duty to protect the business assets.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (2, NULL, 'Chief Risk Officer (CRO)', 'Owns Enterprise Risk Management and Cyber Risk', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (3, NULL, 'Chief Information Security Officer (CISO)', 'Establishes and maintains the enterprise vision, strategy, and program to ensure information assets and technologies are adequately protected.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (4, NULL, 'Data Privacy Officer (DPO)', 'Responsibility is to ensure that the company or organization is correctly protecting individual''s personal data according to current legislation.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (5, NULL, 'Compliance Manager', 'Ensures the company complies with its outside regulatory requirements and internal policies.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (6, NULL, 'Business Owner', 'Owns the systems and processes, accepts risk, defines cyber risk thresholds.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (7, NULL, 'Auditor', 'Responsible for developing, planning, and executing IT audit programs based on risk assessments in a highly integrated audit environment.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (8, NULL, 'Legal Team Member', 'Owns cyber breach communications, approves cyber policies and works with team during a breach response.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (9, NULL, 'Remediator', 'Works to fix control assessment findings, incidents and vulnerabilities.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (10, NULL, 'Vendor Manager', 'Owns vendor management.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (11, NULL, 'SOC Analyst', 'Analyzes incidents and vulnerabilities for false positives in the infrastructure (software, hardware, networks) from cybersecurity tools, defines countermeasures to remedy the detected incidents and vulnerabilities. They may assist in the planning and implementation of security solutions.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (12, NULL, 'Security Engineer', 'Performs cybersecurity monitoring, including forensic and log analysis to detect security incidents, and helps to mount incident response. May investigate new technologies and processes to increase cyber resiliency.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (13, NULL, 'SOC Manager', 'Manages SOC and team', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (14, NULL, 'Security Architect', 'Designs the security infrastructure and roadmap for the organization in terms of cybersecurity tools.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (15, NULL, 'System Administrator', 'Architects and manages permissions for the organization''s security systems.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (16, NULL, 'Breach Response Analyst', 'Analyzes and assesses damage to the digital assets as a result of security incidents, examines available recovery tools and processes, and recommends solutions.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (17, NULL, 'Intrusion Detection Specialist', 'Monitors the digital assets to identify events and traffic indicators that signal intrusion. Documents the damage caused by detected intrusions and recommends safeguards against similar intrusions.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (18, NULL, 'Computer Security Incident Responder', 'A member of team that provides table top exercises and rapid response to security attacks such as viruses and denial-of-service attacks.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (19, NULL, 'Advanced Threat Prevention Technician', 'Analyzes computer viruses and uses advanced threat prevention software to prevent them from delivering their payload.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');
INSERT INTO public.cyber_roles VALUES (20, NULL, 'Penetration Tester', 'Performs penetration testing to identify vulnerabilities and recommend safeguards as preemptive measures. Uses white hack skills to exploit vulnerabilities.', NULL, NULL, '2019-06-13 18:14:06.447954', '2019-06-13 18:14:06.447954');


