INSERT INTO public.data_asset_classifications VALUES (1029, NULL, 'Target Asset', 'M&A Target Asset', NULL, NULL, '2019-11-25 15:24:34.545', '2019-11-25 15:24:34.551', NULL);
INSERT INTO public.data_asset_classifications VALUES (103, NULL, 'Business Crucial', 'A business crucial system is a system whose failure is not critical but has significant impact.', NULL, NULL, '2018-12-27 03:32:38.765219', '2022-04-14 13:22:46.869', 3);
INSERT INTO public.data_asset_classifications VALUES (101, NULL, 'Crown Jewel', 'Crown jewel assets refer to a company''s most prized or valuable assets in terms of its profitability and future prospects. A failure of this type of system results in the company going out of business.  Examples include: Safety-Critical Systems - A system whose failure may result in injury, loss of life or serious environmental damage. An example of a safety-critical system is a control system for a chemical manufacturing plant. Mission-Critical Systems - A system whose failure may result in the failure of some goal-directed activity. An example of a mission-critical system is a navigational system for a spacecraft. Transactional Systems - A system whose failure may result in the failure of some goal-directed activity. An example is a transactional system is one that processes privacy data when the company sells trust. (i.e. Equifax)', NULL, NULL, '2018-12-27 03:32:38.765219', '2022-04-14 13:22:52.873', 1);
INSERT INTO public.data_asset_classifications VALUES (102, NULL, 'Business Critical', 'A business-critical system is a system whose failure may result in very high costs for the business using that system. An example of a business-critical system is the customer accounting system in a bank.', NULL, NULL, '2018-12-27 03:32:38.765219', '2022-04-14 13:23:00.821', 4);


