INSERT INTO public.data_type_classifications VALUES (1035, NULL, 'Claims', 'Insurance claim data is data used for the formal request by a policyholder for coverage or compensation for a covered loss or policy event. ', NULL, NULL, '2019-04-23 10:43:35.808701', '2019-09-18 17:09:57.206', NULL);
INSERT INTO public.data_type_classifications VALUES (1037, NULL, 'Medical', 'Medical data refers to health-related information that is associated with regular patient care or as part of a clinical trial program.', NULL, NULL, '2019-04-23 10:43:35.808701', '2019-09-18 17:11:32.382', NULL);
INSERT INTO public.data_type_classifications VALUES (1039, NULL, 'Underwriting', 'Data associated with the underwriting process.', NULL, NULL, '2019-04-23 10:43:35.808701', '2019-09-18 17:14:15.373', NULL);
INSERT INTO public.data_type_classifications VALUES (1034, NULL, 'Actuarial', 'Actuarial data are the statistics used to calculate various sorts of risk that insurance companies insure people against. ', NULL, NULL, '2019-04-23 10:43:35.808701', '2020-11-24 20:02:43.929', NULL);
INSERT INTO public.data_type_classifications VALUES (1038, NULL, 'State Regulated', 'NAIC state regulated data', NULL, NULL, '2019-04-23 10:43:35.808701', '2022-01-03 13:40:07.702', NULL);
INSERT INTO public.data_type_classifications VALUES (109, NULL, 'Patent', ' Patent information includes the year of invention, technical classification, country of applicant, country of inventor etc., with data going back many years.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 20:35:50.124', NULL);
INSERT INTO public.data_type_classifications VALUES (115, NULL, 'CUI', 'Controlled Unclassified Information is a category of unclassified information within the U.S. Federal government. The CUI program was created by President Obama’s Executive Order 13556 after 9/11 to create a streamlined method for information sharing and safeguarding', NULL, NULL, '2021-09-01 11:59:18.682652', '2022-04-14 13:26:14.029', NULL);
INSERT INTO public.data_type_classifications VALUES (107, NULL, 'Credit Card', 'Credit card data includes the following data elements: cardholder name, card number, card pin, card security code (CVV).', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:36:59.135', NULL);
INSERT INTO public.data_type_classifications VALUES (114, NULL, 'Employee', 'Employee data refers to all information collected by your company about its employees. It includes but is not limited to: basic identifying information (your employees'' age, race or gender) as well as in-depth information about workplace performance.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:39:40.26', NULL);
INSERT INTO public.data_type_classifications VALUES (1044, NULL, 'EU Privacy Data', 'EU data subject data is related to anyone physically within the borders of the EU whose data is being processed while that individual is physically within the Union. For example, a citizen of the EU, who is physically located in the EU, who provides personal information through the purchase of a product. Data elements include Name, Identification number, Location data, Physical address, Email address, IP address, Radio frequency identification tag, Photograph, Video, Voice recording, Biometric data (eye retina, fingerprint, etc.), an online identifier of one or more factors specific to the physical, physiological, genetic, mental, economic, cultural, or social identity of a natural person.', NULL, NULL, '2020-10-14 12:45:22.982', '2022-04-14 13:30:02.878', NULL);
INSERT INTO public.data_type_classifications VALUES (1045, NULL, 'Critical Infrastructure', 'Critical infrastructure data is related to the body of systems, networks and assets that are so essential that their continued operation is required to ensure the security of a given nation, its economy, and the public’s health and/or safety.', NULL, NULL, '2021-03-01 20:13:21.685', '2022-04-14 13:25:04.266', NULL);
INSERT INTO public.data_type_classifications VALUES (113, NULL, 'Financial', 'Financial statements are formal records of the financial activities and position of a business, person, or other entity. Relevant financial information is presented in a structured manner and in a form which is easy to understand.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:42:59.409', NULL);
INSERT INTO public.data_type_classifications VALUES (103, NULL, 'Healthcare', 'Health data is any data "related to health conditions, reproductive outcomes, causes of death, and quality of life" for an individual or population. Health data includes clinical metrics along with environmental, socioeconomic, and behavioral information pertinent to health and wellness.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:43:43.365', NULL);
INSERT INTO public.data_type_classifications VALUES (102, NULL, 'PII', 'Personally Identifiable Information; Any representation of information that permits the identity of an individual to whom the information applies to be reasonably inferred by either direct or indirect means.  Includes Full name, Home address, Email address, Social security number, Passport number, Driver’s license number
Credit card numbers, Date of birth, Telephone number, Owned properties e.g. vehicle identification number (VIN), Login details, Processor or device serial number, Media access control (MAC), Internet Protocol (IP) address, Device IDs, Cookies.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:50:27.417', NULL);
INSERT INTO public.data_type_classifications VALUES (106, NULL, 'Partner Related', 'Partner Data means all data and segments (including but not limited to Personal Data) that are controlled by the Partner or processed by Partner on behalf of Controller and/or originate from Partner''s web and mobile services.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:45:44.054', NULL);
INSERT INTO public.data_type_classifications VALUES (112, NULL, 'Business Data', 'Business data is all the information that is related to a company, such as sales data, customer contact information, and even website traffic statistics.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:35:48.914', NULL);
INSERT INTO public.data_type_classifications VALUES (104, NULL, ' Intellectual Pproperty (IP)', 'Patents, trademarks, copyrights, and trade secrets are valuable assets of the company and understanding how they work and how they are created is critical to knowing how to protect them.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:45:03.502', NULL);
INSERT INTO public.data_type_classifications VALUES (108, NULL, 'Federal', 'Any data provided to or received from the federal government such as an executive agency, by a contractor of an executive agency, or by another organization on behalf of an executive agency.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:42:15.93', NULL);
INSERT INTO public.data_type_classifications VALUES (105, NULL, 'Customer Related', 'Customer data or consumer data refers to all personal, behavioral, and demographic data that is collected by marketing companies and departments from their customer base.', NULL, NULL, '2018-12-27 03:32:38.896651', '2022-04-14 13:38:12.287', NULL);
INSERT INTO public.data_type_classifications VALUES (111, NULL, 'Vendor', 'Any 3rd party data', NULL, NULL, '2018-12-27 03:32:38.896651', '2018-12-27 03:32:38.896651', NULL);
INSERT INTO public.data_type_classifications VALUES (110, NULL, 'Formula', 'Any type of formula data', NULL, NULL, '2018-12-27 03:32:38.896651', '2018-12-27 03:32:38.896651', NULL);
INSERT INTO public.data_type_classifications VALUES (101, NULL, 'Privacy', 'All EU Citizen data ', NULL, NULL, '2018-12-27 03:32:38.896651', '2018-12-27 03:32:38.896651', NULL);


