INSERT INTO public.roles VALUES (1, 'ADMIN', 'System Administrators');
INSERT INTO public.roles VALUES (4, 'USER', 'Users of the system');
INSERT INTO public.roles VALUES (170, 'CEO', 'Chief Executive Officer (CEO) responsible to increase the value of the company.');
INSERT INTO public.roles VALUES (171, 'CRO', 'Chief Risk Officer (CRO) is responsible for the enterprise risk of the company including cyber risk management.');
INSERT INTO public.roles VALUES (172, 'CISO', 'Chief Information Security Officer (CISO). A CISO is a senior-level executive within an organization responsible for establishing and maintaining the enterprise vision, strategy, and cyber security program to ensure digital assets are adequately protected.');
INSERT INTO public.roles VALUES (173, 'CLM', 'Compliance Manager. A compliance manager or officer is an employee whose responsibilities include ensuring the company complies with its outside regulatory requirements and internal policies.');
INSERT INTO public.roles VALUES (174, 'DPO', 'The DPO must ensure that the organization complies with GDPR regulation if it processes EU citizen privacy data regardless of where it is located.  The DPO must have a deep knowledge of the GDPR and an awareness where possible regulatory breaches may occur.');
INSERT INTO public.roles VALUES (175, 'REM', 'Remediator. Fixes vulnerabitlities, incidents and cyber security findings.');
INSERT INTO public.roles VALUES (176, 'SYSOWN', 'System Owner. Is repsonsible for all decisions regarding the use and maintenance of the system.');
INSERT INTO public.roles VALUES (177, 'INFOSEC', 'InfoSec Focal Person. Is the point person that works with a system or process from the information security team.');
INSERT INTO public.roles VALUES (178, 'TSM', 'Task Manager. Owns a specific task or activity in the organization.');
INSERT INTO public.roles VALUES (179, 'PM', 'Project Manager. Manages a specific project in an organization.');
INSERT INTO public.roles VALUES (180, 'BUO', 'BU Owner. Is responsible for all decisions regarding the use and maintenance of the business unit.');
INSERT INTO public.roles VALUES (181, 'AUD', 'Auditor. IT Auditors are responsible for developing, planning, and executing IT audit programs based on risk assessments in a highly integrated audit environment.');
INSERT INTO public.roles VALUES (182, 'RISKMAN', 'Risk Manager. Responsible to create the risk model. Manages risk of a specific nature.');
INSERT INTO public.roles VALUES (183, 'PRCOWN', 'Process Owner. Is responsible for all decisions regarding the use and maintenance of the process.');
INSERT INTO public.roles VALUES (128, 'ORGADMIN', 'Organization Admin. May handle any operations inside organization.');
INSERT INTO public.roles VALUES (186, 'ERM', 'Enterprise Risk Manager. Manages all the systems. Risk Manager only a certain system.');
INSERT INTO public.roles VALUES (187, 'TSO', 'Technical System Owner answers the questions that the system owner cannot. For example: # of records.');
INSERT INTO public.roles VALUES (188, 'VNDOWN', 'Vendor Owner role');
INSERT INTO public.roles VALUES (184, 'VENDOR', 'Employee of the Vendor who is communicate with Organization to ask/answer the questions.');
INSERT INTO public.roles VALUES (185, 'VNDADMIN', 'Vendor Admin who is communicate with Organization to ask/answer the questions.');
INSERT INTO public.roles VALUES (189, 'ORG_READ', 'Full organization reader');
INSERT INTO public.roles VALUES (1025, 'CCPA', 'California Consumer Privacy Act (CCPA) user role.');
INSERT INTO public.roles VALUES (1026, 'TECITOWN', 'Technical IT owner role');
INSERT INTO public.roles VALUES (1027, 'TECBSOWN', 'Technical Business owner role');
INSERT INTO public.roles VALUES (1028, 'DTCLSOWN', 'Data type classification owner role');
INSERT INTO public.roles VALUES (1024, 'CCPA_ADMIN', 'Administrator of the Package Plan for the California Consumer Privacy Act (CCPA_ADMIN) user role.');
INSERT INTO public.roles VALUES (190, 'CFO', 'Chief Financial Officer. Typically, oversees cyber risk and insurance.');


